import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ReactiveFormsModule, UntypedFormBuilder, UntypedFormGroup, Validators } from '@angular/forms';
import { Router, ActivatedRoute } from '@angular/router';
import { first } from 'rxjs/operators';
import { AccountService, AlertService } from '@app/_services';
import { MustMatch } from '@app/_helpers';
import { AlertComponent } from '@app/_components/alert.component';

enum TokenStatus {
  Validating = 'Validating',
  Valid = 'Valid',
  Invalid = 'Invalid'
}

@Component({
  templateUrl: 'reset-password.component.html',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, AlertComponent]
})
export class ResetPasswordComponent implements OnInit {
  TokenStatus = TokenStatus;
  tokenStatus = TokenStatus.Validating;
  token!: string;
  form!: UntypedFormGroup;
  loading = false;
  submitted = false;

  constructor(
    private formBuilder: UntypedFormBuilder,
    private route: ActivatedRoute,
    private router: Router,
    private accountService: AccountService,
    private alertService: AlertService
  ) { }

  ngOnInit() {
    this.token = this.route.snapshot.queryParams['token'];
    this.form = this.formBuilder.group({
      password: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', Validators.required]
    }, { validators: MustMatch('password', 'confirmPassword') });

    this.accountService.validateResetToken(this.token)
      .pipe(first())
      .subscribe({
        next: () => { this.tokenStatus = TokenStatus.Valid; },
        error: () => { this.tokenStatus = TokenStatus.Invalid; }
      });
  }

  get f() { return this.form.controls; }

  onSubmit() {
    this.submitted = true;
    this.alertService.clear();
    if (this.form.invalid) return;
    this.loading = true;
    this.accountService.resetPassword(this.token, this.f['password'].value, this.f['confirmPassword'].value)
      .pipe(first())
      .subscribe({
        next: () => {
          this.alertService.success('Password reset successful, you can now login', { keepAfterRouteChange: true });
          this.router.navigate(['/account/login']);
        },
        error: (error: string) => {
          this.alertService.error(error, { id: 'reset-password-alert' });
          this.loading = false;
        }
      });
  }
}
<h4 class="card-title mb-4">Reset Password</h4>
<alert id="reset-password-alert"></alert>

<div *ngIf="tokenStatus === TokenStatus.Validating">
  <span class="spinner-border spinner-border-sm me-1"></span>
  Validating token...
</div>

<div *ngIf="tokenStatus === TokenStatus.Invalid">
  <p class="text-danger">Token validation failed, please try again.</p>
  <a routerLink="/account/forgot-password">Get a new reset password link</a>
</div>

<form *ngIf="tokenStatus === TokenStatus.Valid" [formGroup]="form" (ngSubmit)="onSubmit()">
  <div class="mb-3">
    <label class="form-label">Password</label>
    <input type="password" formControlName="password" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['password'].errors }" />
    <div *ngIf="submitted && f['password'].errors" class="invalid-feedback">
      <div *ngIf="f['password'].errors['required']">Password is required</div>
      <div *ngIf="f['password'].errors['minlength']">Password must be at least 6 characters</div>
    </div>
  </div>
  <div class="mb-3">
    <label class="form-label">Confirm Password</label>
    <input type="password" formControlName="confirmPassword" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['confirmPassword'].errors }" />
    <div *ngIf="submitted && f['confirmPassword'].errors" class="invalid-feedback">
      <div *ngIf="f['confirmPassword'].errors['required']">Confirm Password is required</div>
      <div *ngIf="f['confirmPassword'].errors['mustMatch']">Passwords must match</div>
    </div>
  </div>
  <div class="d-flex justify-content-between">
    <button [disabled]="loading" class="btn btn-primary">
      <span *ngIf="loading" class="spinner-border spinner-border-sm me-1"></span>
      Reset Password
    </button>
    <a routerLink="/account/login">Cancel</a>
  </div>
</form>
